import { agentConfig } from '@mastra/core/agent'
import { ingestMeetingWorkflow } from './workflows/ingest-meeting'

export default agentConfig({
  model: 'anthropic/claude-haiku-4-5',
  workflows: { ingestMeetingWorkflow },
})

import { createTool } from '@mastra/core/tools'
import { z } from 'zod'

export default createTool({
  id: 'save_notes',
  description:
    'Saves the structured meeting notes. Call this once the transcript has been fully processed.',
  inputSchema: z.object({
    summary: z.string(),
    decisions: z.array(z.string()),
    actionItems: z.array(z.object({
      owner: z.string(),
      task: z.string(),
    })),
    openQuestions: z.array(z.string()),
  }),
  execute: async (inputData) => {
    return inputData
  },
})

import { createTool } from '@mastra/core/tools'
import { z } from 'zod'

const ZOOM_API = 'https://api.zoom.us/v2'

const headers = () => ({
  Authorization: `Bearer ${process.env.ZOOM_JWT_TOKEN ?? ''}`,
  'Content-Type': 'application/json',
})

export default createTool({
  id: 'list_meetings',
  description: 'Lists recent Zoom meetings for the authenticated user.',
  inputSchema: z.object({
    userId: z
      .string()
      .optional()
      .describe('Zoom user ID (defaults to "me")'),
    limit: z
      .number()
      .int()
      .min(1)
      .max(300)
      .optional()
      .describe('Maximum number of meetings to return'),
  }),
  outputSchema: z.object({
    meetings: z.array(
      z.object({
        id: z.string(),
        topic: z.string(),
        startTime: z.string(),
        duration: z.number(),
      }),
    ),
  }),
  execute: async (inputData) => {
    const { userId = 'me', limit = 30 } = inputData
    const url = new URL(`${ZOOM_API}/users/${userId}/meetings`)
    url.searchParams.set('type', 'scheduled')
    url.searchParams.set('page_size', String(Math.min(limit, 300)))
    const data = await fetch(url.toString(), { headers: headers() }).then(
      (r) => r.json(),
    )
    return {
      meetings: ((data.meetings ?? []) as any[]).map((m) => ({
        id: String(m.id),
        topic: m.topic as string,
        startTime: m.start_time as string,
        duration: m.duration as number,
      })),
    }
  },
})

import { createTool } from '@mastra/core/tools'
import { z } from 'zod'

const ZOOM_API = 'https://api.zoom.us/v2'

const headers = () => ({
  Authorization: `Bearer ${process.env.ZOOM_JWT_TOKEN ?? ''}`,
  'Content-Type': 'application/json',
})

export default createTool({
  id: 'get_transcript',
  description: 'Gets the transcript for a specific Zoom meeting.',
  inputSchema: z.object({
    meetingId: z.string().describe('Zoom meeting ID'),
  }),
  outputSchema: z.object({
    transcript: z.array(
      z.object({
        speaker: z.string(),
        timestamp: z.string(),
        text: z.string(),
      }),
    ),
  }),
  execute: async (inputData) => {
    const { meetingId } = inputData
    const url = `${ZOOM_API}/meetings/${meetingId}/recordings`
    const data = await fetch(url, { headers: headers() }).then((r) =>
      r.json(),
    )
    const recording = ((data.recording_files ?? []) as any[]).find(
      (r: any) => r.recording_type === 'audio_transcript',
    )
    if (!recording?.download_url) {
      return { transcript: [] }
    }
    const transcriptText = await fetch(
      `${recording.download_url}?access_token=${process.env.ZOOM_JWT_TOKEN ?? ''}`,
    ).then((r) => r.text())
    const lines = transcriptText.split('\n').filter(Boolean)
    return {
      transcript: lines.map((line) => {
        const match = line.match(
          /^(.+?)\s*\((\d{2}:\d{2}:\d{2})\)\s*(.+)$/,
        )
        if (!match) return { speaker: 'Unknown', timestamp: '', text: line }
        return {
          speaker: match[1].trim(),
          timestamp: match[2],
          text: match[3].trim(),
        }
      }),
    }
  },
})

import { createWorkflow, createStep } from '@mastra/core/workflows'
import { z } from 'zod'

const fetchTranscript = createStep({
  id: 'fetch-transcript',
  description: 'Fetches transcript from Zoom for a given meeting',
  inputSchema: z.object({
    meetingId: z.string(),
  }),
  outputSchema: z.object({
    meetingId: z.string(),
    transcript: z.array(
      z.object({
        speaker: z.string(),
        timestamp: z.string(),
        text: z.string(),
      }),
    ),
  }),
  execute: async ({ inputData, mastra }) => {
    const agent = mastra?.getAgent('meetingNotesAgent')
    const response = await agent?.generate(
      `Fetch the transcript for Zoom meeting ${inputData.meetingId} using the get_transcript tool.`,
    )
    const data = JSON.parse(response?.text || '{"transcript":[]}')
    return {
      meetingId: inputData.meetingId,
      transcript: data.transcript ?? [],
    }
  },
})

const summarizeMeeting = createStep({
  id: 'summarize-meeting',
  description: 'Uses agent to create a structured summary from the transcript',
  inputSchema: z.object({
    meetingId: z.string(),
    transcript: z.array(
      z.object({
        speaker: z.string(),
        timestamp: z.string(),
        text: z.string(),
      }),
    ),
  }),
  outputSchema: z.object({
    meetingId: z.string(),
    summary: z.string(),
    decisions: z.array(z.string()),
    actionItems: z.array(
      z.object({
        owner: z.string(),
        task: z.string(),
      }),
    ),
    openQuestions: z.array(z.string()),
  }),
  execute: async ({ inputData, mastra }) => {
    const transcriptText = inputData.transcript
      .map((t) => `[${t.timestamp}] ${t.speaker}: ${t.text}`)
      .join('\n')

    const agent = mastra?.getAgent('meetingNotesAgent')
    const response = await agent?.generate(
      `Analyze the following meeting transcript and produce a structured summary.

Transcript:
${transcriptText}

Return ONLY a JSON object with this exact format (no markdown, no explanation):
{
  "summary": "Brief overview of the meeting",
  "decisions": ["Decision 1", "Decision 2"],
  "actionItems": [{"owner": "Person", "task": "What to do"}],
  "openQuestions": ["Question 1", "Question 2"]
}`,
    )

    const text = response?.text || '{}'
    const jsonMatch = text.match(/\{[\s\S]*\}/)
    const result = jsonMatch ? JSON.parse(jsonMatch[0]) : {}

    return {
      meetingId: inputData.meetingId,
      summary: result.summary ?? '',
      decisions: result.decisions ?? [],
      actionItems: result.actionItems ?? [],
      openQuestions: result.openQuestions ?? [],
    }
  },
})

export const ingestMeetingWorkflow = createWorkflow({
  id: 'ingest-meeting-workflow',
  inputSchema: z.object({
    meetingId: z.string(),
  }),
  outputSchema: z.object({
    meetingId: z.string(),
    summary: z.string(),
    decisions: z.array(z.string()),
    actionItems: z.array(
      z.object({
        owner: z.string(),
        task: z.string(),
      }),
    ),
    openQuestions: z.array(z.string()),
  }),
})
  .then(fetchTranscript)
  .then(summarizeMeeting)

ingestMeetingWorkflow.commit()
